// @/src/hooks/useNotification.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification-element';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = (): {
  notificationElem: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
} => {
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const notification = document.querySelector('('huel-notification');
    setNotificationElem(notification as HTMLHuelNotificationElement | null);
  }, []);

  const notify = async (props: NotificationProps): Promise<void> => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElem, notify };
};

